import {Criterium, CriteriumName, fetchTableRows, Grouping, IsSelectedItem, Operator, postNameValueList, Veld} from "../werklijst/criteria";
import {getTable, getWerklijstTableRef, InfoBarTableFetchListener} from "./loadAnyTable";
import {getImmediateText} from "../globals";
import {CheckSumBuilder, FetchedTable, TableFetcher, TableFetchListener} from "./tableFetcher";

interface WerklijstItemDefinition {
    id: string;
    name: string;
}

export interface PreparedWerklijst {
    fetchTable(listener: TableFetchListener | undefined, clearCache: boolean): Promise<FetchedTable>;
}

export interface CriteriaBuilder {
    addCriterium(name: CriteriumName, operator: Operator, values: string[]): void;
    addFields(fields: Veld[]): void;
    sendSettings(): Promise<PreparedWerklijst>;
    fetchAvailableSubjects(): Promise<{name: string, value: string}[]>;
    initialize(reset: boolean): Promise<void>;
}

export function createWerklijstBuilderWithoutReset(schoolYear: string, grouping: Grouping, preselectedFields: string[], criteriaString: string) {
    return WerklijstBuilder.fetch(schoolYear, grouping, false, preselectedFields, criteriaString);
}

export function createWerklijstBuilderWithReset(schoolYear: string, grouping: Grouping) {
    return WerklijstBuilder.fetch(schoolYear, grouping, true, [], "");
}

class WerklijstBuilder implements CriteriaBuilder, PreparedWerklijst {
    private readonly schoolYear: string;
    private readonly grouping: Grouping;
    criteria: Criterium[] = [];
    fields: Veld[];
    private criteriaDefs: WerklijstItemDefinition[];
    private fieldDefs: WerklijstItemDefinition[];
    private preselectedFields: string[] = [];
    private criteriaString: string = "";

    private constructor(schoolYear: string, grouping: Grouping) {
        this.schoolYear = schoolYear;
        this.grouping = grouping;
        this.criteria = [];
        this.fields = [];
    }

    private getCheckSum() {
        return this.criteria.map(c => c.name + c.operator + c.values.join()).join()
            + this.fields.map(f => f.text).join()
            + this.criteriaString;
    }

    static async fetch(schoolYear: string, grouping: Grouping, reset: boolean, preselectedFields: string[], criteriaString: string) {
        let builder = new WerklijstBuilder(schoolYear, grouping);
        await builder.initialize(reset);
        builder.criteriaDefs = await this.fetchCriteriumDefinitions();
        builder.fieldDefs = await this.fetchFieldDefinitions();
        builder.criteriaString = criteriaString;
        if(!reset)
            builder.setPreselectedFields(preselectedFields);
        return builder as CriteriaBuilder;
    }

    async initialize(reset: boolean) {
        await fetch("view.php?args=leerlingen-werklijst");
        await fetch("views/leerlingen/werklijst/index.view.php"); //get header block (schooljaar, 1 lijn per..., criteria, velden)
        if(!reset) {
            await postNameValueList("/views/leerlingen/werklijst/session.opslaan.php", [{name: "schooljaar", value: this.schoolYear}, {name: "groepering", value: this.grouping}]);
            return;
        }
        await postNameValueList("/views/leerlingen/werklijst/session.opslaan.php", [{name:"reset", value:"1"}]);
        await postNameValueList("/views/leerlingen/werklijst/session.opslaan.php", [{name: "schooljaar", value: this.schoolYear}, {name: "groepering", value: this.grouping}]);
    }

    static async fetchDefinitions(url:string, idTagName: string, nameSelector: string) {
        let rows = await fetchTableRows(await fetch(url));
        let defs: { id: string; name: string }[] = [];
        for (let row of rows) {
            let id = row.dataset[idTagName];
            if (id) {
                let element = row.querySelector(nameSelector) as HTMLElement;
                let name = getImmediateText(element).trim();
                defs.push({id, name});
            }
        }
        return defs;
    }

    static async fetchCriteriumDefinitions() {
        return this.fetchDefinitions("/views/leerlingen/werklijst/criteria/toevoegen/criteria.results.php", "criterium_id", "td");
    }

    static async fetchFieldDefinitions() {
        return this.fetchDefinitions("/views/leerlingen/werklijst/velden/toevoegen/velden.results.php", "veld_id", "td:nth-child(2)");
    }

    async sendCriteria() {
        for (const c of this.criteria) {
            let codes = await this.addCodesForCriterium(c.name, c.values);
            //todo: send operator
            await postNameValueList("/views/leerlingen/werklijst/criteria/wijzigen.opslaan.php", [
                {name: "criterium_id", value: codes.postId},
                {name: "value", value: codes.values.join()}
            ]);
        }
    }

    async sendSettings() {
        await this.sendFields(this.fields);
        await this.sendCriteria();
        return this as PreparedWerklijst;
    }

    async fetchTable(listener: InfoBarTableFetchListener | undefined, clearCache: boolean) {
        let tableRef = await getWerklijstTableRef();
        return getTable(tableRef, listener, clearCache, (_: TableFetcher) => this.getCheckSum());
        //todo: keep state of builder: TABLE_FETCHED.
    }

    addCriterium(name: CriteriumName, operator: Operator, values: string[]) {
        this.criteria.push({name, operator, values});
    }

    addFields(fields: Veld[]) {
        this.fields.push(...fields);
    }

    private async addCodesForCriterium(criterium: CriteriumName, items: (string[] | IsSelectedItem)) {
        let defs = await this.fetchMultiSelectDefinitions(criterium);
        let codes = textToCodes(items, defs.defs);
        return {postId: defs.postId, operator: "TDOO", values: codes};
    }

    async fetchAvailableSubjects() {
        let defs = await this.fetchMultiSelectDefinitions(CriteriumName.Vak);
        return Array.from(defs.defs).map((vak) => {  return {name: vak[0], value: vak[1]}; });
    }

    async fetchMultiSelectDefinitions(criterium: CriteriumName) {
        let critId = this.criteriaDefs.find(c => c.name === criterium)!.id;
        await postNameValueList("/views/leerlingen/werklijst/criteria/toevoegen/toevoegen.opslaan.php", [{name:"criterium_id", value:critId}]);
        let text = await fetch("/views/leerlingen/werklijst/criteria/criteria.div.php").then(res => res.text());
        const template = document.createElement('template');
        template.innerHTML = text;
        let tr = template.content.querySelector(`tr[data-criterium_id="${critId}"]`)!;
        let select = tr.querySelector(`td:nth-child(3) select`) as HTMLSelectElement;
        let defs = select.querySelectorAll(`option`);
        return {
            postId: select.dataset.postId!,
            defs: Array.from(defs).map((def: HTMLOptionElement) => [def.label, def.value]),
        };
    }

    async sendFields(fields: Veld[]) {
        let fieldsToActuallySend = fields.filter(f => !this.preselectedFields.includes(f.text));
        for (let field of fieldsToActuallySend) {
            let fieldDef = this.fieldDefs.find(f => f.name === field.text);
            if (fieldDef) {
                await postNameValueList("/views/leerlingen/werklijst/velden/toevoegen/wijzigen.opslaan.php", [{name:"veld_id", value:fieldDef.id}, {name:"selected", value:"1"}]);
            }
        }
    }

    private setPreselectedFields(preselectedFields: string[]) {
        this.preselectedFields = preselectedFields;
    }
}

function textToCodes(items: (string[] | IsSelectedItem), vakDefs: string[][]) {
    let filtered: string[][];
    if (typeof items === 'function') {
        let isIncluded = items;
        filtered = vakDefs.filter((vakDef) => isIncluded(vakDef[0]));
    } else {
        filtered = vakDefs.filter((vakDef) => (items as string[]).includes(vakDef[0]));
    }
    return filtered.map(vakDef => vakDef[1]);
}

